static int Dtool_Traverse_PythonCallbackObject(PyObject *self, visitproc visit, void *arg) {
  // If the only reference remaining is the one held by the Python wrapper,
  // report the circular reference to Python's GC, so that it can break it.
  PythonCallbackObject *local_this;
  DTOOL_Call_ExtractThisPointerForType(self, &Dtool_PythonCallbackObject, (void**)(&local_this));
  if (local_this == nullptr) {
    return 0;
  }
  if (local_this->get_ref_count() == (int)((Dtool_PyInstDef *)self)->_memory_rules) {
    Py_VISIT(self);
  }
  return 0;
}

